#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int L, N;
        scanf("%d %d", &L, &N);
        char S[L + 1];
        scanf("%s", S);
        char grid[N][N + 1];
        for (int i = 0; i < N; i++) {
            scanf("%s", grid[i]);
        }
        int xor = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (grid[i][j] == '.') {
                    int count = 0;
                    int x = i, y = j;
                    for (int k = 0; k < L; k++) {
                        if (S[k] == 'R') {
                            if (y + 1 < N && grid[x][y + 1] == '.') {
                                y++;
                            } else {
                                break;
                            }
                        } else if (S[k] == 'L') {
                            if (y - 1 >= 0 && grid[x][y - 1] == '.') {
                                y--;
                            } else {
                                break;
                            }
                        } else if (S[k] == 'U') {
                            if (x - 1 >= 0 && grid[x - 1][y] == '.') {
                                x--;
                            } else {
                                break;
                            }
                        } else if (S[k] == 'D') {
                            if (x + 1 < N && grid[x + 1][y] == '.') {
                                x++;
                            } else {
                                break;
                            }
                        }
                        count++;
                    }
                    xor ^= count;
                }
            }
        }
        printf("%d\n", xor);
    }
    return 0;
}

