                        if y + 1 < N and grid[x][y + 1] == '.':
                            y += 1
                        else:
                            break
                    elif S[k] == 'L':
                        if y - 1 >= 0 and grid[x][y - 1] == '.':
                            y -= 1
                        else:
                            break
                    elif S[k] == 'U':
                        if x - 1 >= 0 and grid[x - 1][y] == '.':
                            x -= 1
                        else:
                            break
