for (let i = 0; i < T; i++) {
    const [L, N] = readline().split(' ').map(Number);
    const S = readline().trim();
    const grid = [];
    for (let j = 0; j < N; j++) {
        grid.push(readline().trim().split(''));
    }
    let xor = 0;
    for (let x = 0; x < N; x++) {
        for (let y = 0; y < N; y++) {
            if (grid[x][y] === '.') {
                let count = 0;
                let currX = x, currY = y;
                for (let k = 0; k < L; k++) {
                    if (S[k] === 'R') {
                        if (currY + 1 < N && grid[currX][currY + 1] === '.') {
                            currY++;
                        } else {
                            break;
                        }
                    } else if (S[k] === 'L') {
                        if (currY - 1 >= 0 && grid[currX][currY - 1] === '.') {
                            currY--;
                        } else {
                            break;
                        }
                    } else if (S[k] === 'U') {
                        if (currX - 1 >= 0 && grid[currX - 1][currY] === '.') {
                            currX--;
                        } else {
                            break;
                        }
                    } else if (S[k] === 'D') {
                        if (currX + 1 < N && grid[currX + 1][currY] === '.') {
                            currX++;
                        } else {
                            break;
                        }
                    }
                    count++;
                }
                xor ^= count;
            }
        }
    }
    console.log(xor);
}

